import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface ServiceSpend {
  service: string;
  cost: number;
}

interface CloudCostData {
  currentSpend: {
    total: number;
    savingsOpportunity: number;
  };
  spendByService: ServiceSpend[];
  spendTrend: number[];
}

export default function Widget() {
  const cloudCostData = response.data as CloudCostData;
  const { currentSpend, spendByService, spendTrend } = cloudCostData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#212121', color: '#E0E0E0' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107' }}>
              Cloud Cost Optimization
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Current Month Spend
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              ${currentSpend.total.toLocaleString()}
            </Typography>
            <Typography variant="caption" sx={{ color: '#FFC107' }}>
              Savings Opportunity: ${currentSpend.savingsOpportunity.toLocaleString()}
            </Typography>
          </Box>

          <Divider sx={{ bgcolor: '#424242' }} />

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: spendTrend,
                  color: '#FFC107',
                  label: 'Trend',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  id: 'months',
                  data: spendTrend.map((_, index) => `M${index + 1}`),
                },
              ]}
              yAxis={[{ id: 'spend', label: 'Spend ($)' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#BDBDBD' }}
              />
              <ChartsYAxis
                axisId="spend"
                tickLabelStyle={{ fontSize: 10, fill: '#BDBDBD' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack spacing={1}>
            {spendByService.map((serviceSpend) => (
              <Box key={serviceSpend.service} display="flex" justifyContent="space-between">
                <Typography variant="body2" sx={{ color: '#E0E0E0' }}>
                  {serviceSpend.service}
                </Typography>
                <Typography variant="body2" sx={{ color: '#E0E0E0' }}>
                  ${serviceSpend.cost.toLocaleString()}
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
